+using System;
+using System.Collections.Generic;
+using System.Linq;
+
+namespace OracleV5
+{
+    public static class Tests_VIXMonitor
+    {
+        public static void RunTests()
+        {
+            Console.WriteLine("Running VIXMonitor Tests...");
+            TestReset();
+            Console.WriteLine("VIXMonitor Tests Passed!");
+        }
+
+        public static void TestReset()
+        {
+            var monitor = new VIXMonitor(lookback: 20);
+
+            // 1. Initial state check
+            if (monitor.GetFearLevel() != 0.0)
+                throw new Exception($"[VIX_TEST] Initial FearLevel should be 0, got {monitor.GetFearLevel()}");
+
+            // 2. Populate and verify state
+            for (int i = 1; i <= 15; i++)
+                monitor.Update(20.0 + i);
+
+            var midSnapshot = monitor.GetSnapshot();
+            if (!midSnapshot.IsReady)
+                throw new Exception("[VIX_TEST] Monitor should be ready after 15 updates (min 10)");
+
+            if (midSnapshot.FearLevel != 35.0)
+                throw new Exception($"[VIX_TEST] Expected FearLevel 35.0, got {midSnapshot.FearLevel}");
+
+            // 3. Reset and verify
+            monitor.Reset();
+
+            if (monitor.GetFearLevel() != 0.0)
+                throw new Exception($"[VIX_TEST] FearLevel should be 0 after Reset, got {monitor.GetFearLevel()}");
+
+            var finalSnapshot = monitor.GetSnapshot();
+            if (finalSnapshot.IsReady)
+                throw new Exception("[VIX_TEST] Monitor should NOT be ready after Reset");
+
+            if (finalSnapshot.Reason != "No VIX history")
+                throw new Exception($"[VIX_TEST] Expected 'No VIX history' reason, got '{finalSnapshot.Reason}'");
+
+            Console.WriteLine("TestReset: PASSED");
+        }
+    }
+}
